"""
Test cases for accept_channel shutdown_script parameter.
Verifies: channel acceptance with shutdown script and balance refund behavior on channel shutdown.
"""
import time

import pytest

from framework.basic_fiber import FiberTest
from framework.config import DEFAULT_MIN_DEPOSIT_CKB
from framework.constants import Amount, Timeout, ChannelState, PaymentStatus, FeeRate, Currency, HashAlgorithm


class TestShutdownScript(FiberTest):
    """
    Test accept_channel with shutdown_script parameter.
    Verifies: channel can be accepted with shutdown script, and shutdown triggers balance refund to shutdown script.
    """

    @pytest.mark.skip("repeat")
    def test_shutdown_script_none(self):
        """
        Test case for shutdown_script: none.
        Skipped: duplicate test case.
        """

    def test_ckb_shutdown_script(self):
        """
        Test that shutdown_script triggers balance refund to shutdown script on channel shutdown.
        Step 1: Generate new account and get node info.
        Step 2: fiber1 opens channel with fiber2.
        Step 3: fiber2 accepts channel with shutdown script.
        Step 4: Wait for channel ready.
        Step 5: fiber1 sends payment to fiber2.
        Step 6: fiber1 shuts down channel.
        Step 7: Verify balance refund to shutdown script.
        """
        # Step 1: Generate new account and get node info
        new_account_private_key = self.generate_account(0)
        new_account = self.Ckb_cli.util_key_info_by_private_key(new_account_private_key)
        node_info = self.fiber1.get_client().node_info()
        open_channel_auto_accept_min_ckb_funding_amount = node_info[
            "open_channel_auto_accept_min_ckb_funding_amount"
        ]

        # Step 2: fiber1 opens channel with fiber2
        temporary_channel = self.fiber1.get_client().open_channel(
            {
                "peer_id": self.fiber2.get_peer_id(),
                "funding_amount": hex(
                    int(open_channel_auto_accept_min_ckb_funding_amount, 16) - 1
                ),
                "public": True,
            }
        )
        time.sleep(Timeout.POLL_INTERVAL)

        # Step 3: fiber2 accepts channel with shutdown script
        self.fiber2.get_client().accept_channel(
            {
                "temporary_channel_id": temporary_channel["temporary_channel_id"],
                "funding_amount": node_info["auto_accept_channel_ckb_funding_amount"],
                "shutdown_script": self.get_account_script(new_account_private_key),
            }
        )

        # Step 4: Wait for channel ready
        self.wait_for_channel_state(
            self.fiber1.get_client(),
            self.fiber2.get_peer_id(),
            ChannelState.CHANNEL_READY,
            timeout=Timeout.CHANNEL_READY,
        )

        # Step 5: fiber1 sends payment to fiber2
        payment_preimage = self.generate_random_preimage()
        invoice_balance = Amount.ckb(0.1)
        invoice = self.fiber2.get_client().new_invoice(
            {
                "amount": hex(invoice_balance),
                "currency": Currency.FIBD,
                "description": "test invoice generated by node2",
                "expiry": "0xe10",
                "payment_preimage": payment_preimage,
                "hash_algorithm": HashAlgorithm.SHA256,
            }
        )
        before_channel = self.fiber1.get_client().list_channels({})

        payment = self.fiber1.get_client().send_payment(
            {
                "invoice": invoice["invoice_address"],
            }
        )
        self.wait_payment_state(
            self.fiber1, payment["payment_hash"], PaymentStatus.SUCCESS, timeout=Timeout.PAYMENT_SUCCESS
        )
        after_channel = self.fiber1.get_client().list_channels({})
        assert (
            int(before_channel["channels"][0]["local_balance"], 16)
            - int(after_channel["channels"][0]["local_balance"], 16)
            == invoice_balance
        )

        channels = self.fiber1.get_client().list_channels(
            {"peer_id": self.fiber2.get_peer_id()}
        )
        N1N2_CHANNEL_ID = channels["channels"][0]["channel_id"]
        self.fiber1.get_client().graph_channels()
        before_balance1 = self.Ckb_cli.wallet_get_capacity(
            self.account1["address"]["testnet"]
        )
        before_balance2 = self.Ckb_cli.wallet_get_capacity(
            self.account2["address"]["testnet"]
        )

        # Step 6: fiber1 shuts down channel
        self.fiber1.get_client().shutdown_channel(
            {
                "channel_id": N1N2_CHANNEL_ID,
                "close_script": self.get_account_script(self.Config.ACCOUNT_PRIVATE_1),
                "fee_rate": hex(FeeRate.DEFAULT),
            }
        )
        tx_hash = self.wait_and_check_tx_pool_fee(FeeRate.DEFAULT, False, Timeout.MEDIUM)
        self.Miner.miner_until_tx_committed(self.node, tx_hash)

        # Step 7: Verify balance refund to shutdown script

        after_balance2 = self.Ckb_cli.wallet_get_capacity(
            self.fiber2.get_account()["address"]["testnet"]
        )
        after_new_balance = self.Ckb_cli.wallet_get_capacity(
            new_account["address"]["testnet"]
        )
        assert after_balance2 - before_balance2 == 0
        assert after_new_balance == 99.1

    def test_udt_shutdown_script(self):
        """
        Test that shutdown_script triggers UDT balance refund to shutdown script on channel shutdown.
        Step 1: Generate new account.
        Step 2: fiber1 opens UDT channel with fiber2.
        Step 3: fiber2 accepts channel with shutdown script.
        Step 4: Wait for channel ready.
        Step 5: fiber1 sends UDT payment to fiber2.
        Step 6: fiber1 shuts down channel.
        Step 7: Verify UDT balance refund to shutdown script.
        """
        # Step 1: Generate new account
        new_account_private_key = self.generate_account(0)

        # Step 2: fiber1 opens UDT channel with fiber2
        temporary_channel = self.fiber1.get_client().open_channel(
            {
                "peer_id": self.fiber2.get_peer_id(),
                "funding_amount": hex(Amount.udt(5)),
                "public": True,
                "funding_udt_type_script": self.get_account_udt_script(
                    self.fiber1.account_private
                ),
            }
        )
        time.sleep(Timeout.POLL_INTERVAL)

        # Step 3: fiber2 accepts channel with shutdown script
        self.fiber2.get_client().accept_channel(
            {
                "temporary_channel_id": temporary_channel["temporary_channel_id"],
                "funding_amount": "0x0",
                "shutdown_script": self.get_account_script(new_account_private_key),
            }
        )

        # Step 4: Wait for channel ready
        self.wait_for_channel_state(
            self.fiber1.get_client(),
            self.fiber2.get_peer_id(),
            ChannelState.CHANNEL_READY,
            timeout=Timeout.CHANNEL_READY,
        )

        # Step 5: fiber1 sends UDT payment to fiber2
        payment_preimage = self.generate_random_preimage()
        invoice_balance = Amount.udt(1)
        invoice = self.fiber2.get_client().new_invoice(
            {
                "amount": hex(invoice_balance),
                "currency": Currency.FIBD,
                "description": "test invoice generated by node2",
                "expiry": "0xe10",
                "payment_preimage": payment_preimage,
                "hash_algorithm": HashAlgorithm.SHA256,
                "udt_type_script": self.get_account_udt_script(
                    self.fiber1.account_private
                ),
            }
        )
        before_channel = self.fiber1.get_client().list_channels({})

        payment = self.fiber1.get_client().send_payment(
            {
                "invoice": invoice["invoice_address"],
            }
        )
        self.wait_payment_state(
            self.fiber1, payment["payment_hash"], PaymentStatus.SUCCESS, timeout=Timeout.PAYMENT_SUCCESS
        )
        after_channel = self.fiber1.get_client().list_channels({})
        assert (
            int(before_channel["channels"][0]["local_balance"], 16)
            - int(after_channel["channels"][0]["local_balance"], 16)
            == invoice_balance
        )

        channels = self.fiber1.get_client().list_channels(
            {"peer_id": self.fiber2.get_peer_id()}
        )
        N1N2_CHANNEL_ID = channels["channels"][0]["channel_id"]
        self.fiber1.get_client().graph_channels()

        before_account1 = self.udtContract.list_cell(
            self.node.getClient(),
            self.get_account_script(self.fiber1.account_private)["args"],
            self.get_account_script(self.fiber1.account_private)["args"],
        )
        before_account2 = self.udtContract.list_cell(
            self.node.getClient(),
            self.get_account_script(self.fiber1.account_private)["args"],
            self.get_account_script(self.fiber2.account_private)["args"],
        )

        # Step 6: fiber1 shuts down channel
        self.fiber1.get_client().shutdown_channel(
            {
                "channel_id": N1N2_CHANNEL_ID,
                "close_script": self.get_account_script(self.Config.ACCOUNT_PRIVATE_1),
                "fee_rate": hex(FeeRate.DEFAULT),
            }
        )
        tx_hash = self.wait_and_check_tx_pool_fee(FeeRate.DEFAULT, False, Timeout.CHANNEL_READY)
        self.Miner.miner_until_tx_committed(self.node, tx_hash)

        # Step 7: Verify UDT balance refund to shutdown script
        after_account1 = self.udtContract.list_cell(
            self.node.getClient(),
            self.get_account_script(self.fiber1.account_private)["args"],
            self.get_account_script(self.fiber1.account_private)["args"],
        )
        after_account2 = self.udtContract.list_cell(
            self.node.getClient(),
            self.get_account_script(self.fiber1.account_private)["args"],
            self.get_account_script(self.fiber2.account_private)["args"],
        )
        after_new_account = self.udtContract.list_cell(
            self.node.getClient(),
            self.get_account_script(self.fiber1.account_private)["args"],
            self.get_account_script(new_account_private_key)["args"],
        )
        assert after_account1[-1]["balance"] == Amount.udt(4)
        assert after_new_account[-1]["balance"] == Amount.udt(1)

    def test_shutdown_script_too_long_gt_funding_amount(self):
        """
        shutdown_script with data too big causes CKB not enough; expect funding amount error.
        Step 1: Open channel with funding below auto-accept minimum.
        Step 2: Accept with shutdown_script that requires more CKB than funding; expect exception.
        Step 3: Assert error message contains expected funding amount requirement.
        """
        node_info = self.fiber1.get_client().node_info()
        open_channel_auto_accept_min_ckb_funding_amount = node_info[
            "open_channel_auto_accept_min_ckb_funding_amount"
        ]

        # Step 1: Open channel with funding below auto-accept minimum
        temporary_channel = self.fiber1.get_client().open_channel(
            {
                "peer_id": self.fiber2.get_peer_id(),
                "funding_amount": hex(
                    int(open_channel_auto_accept_min_ckb_funding_amount, 16) - 1
                ),
                "public": True,
            }
        )
        time.sleep(Timeout.POLL_INTERVAL)
        # Step 2: Accept with shutdown_script that requires more CKB than funding
        with pytest.raises(Exception) as exc_info:
            self.fiber2.get_client().accept_channel(
                {
                    "temporary_channel_id": temporary_channel["temporary_channel_id"],
                    "funding_amount": hex(DEFAULT_MIN_DEPOSIT_CKB),
                    "shutdown_script": {
                        "code_hash": "0x9bd7e06f3ecf4be0f2fcd2188b23f1b9fcc88e5d4b65a8637b17723bbda3cce8",
                        "hash_type": "type",
                        "args": "",
                    },
                }
            )
        # Step 3: Assert error message contains expected funding amount requirement
        expected_error_message = "The funding amount (9900000000) should be greater than or equal to 147200000000"
        assert expected_error_message in exc_info.value.args[0], (
            f"Expected substring '{expected_error_message}' "
            f"not found in actual string '{exc_info.value.args[0]}'"
        )

    def test_shutdown_script_too_long(self):
        """
        shutdown_script with large data args: channel accepts, payment and shutdown succeed.
        Step 1: fiber1 open channel with fiber2 (funding below auto-accept).
        Step 2: fiber2 accept channel with large shutdown_script args and sufficient funding.
        Step 3: Wait for channel ready; fiber1 send payment to fiber2.
        Step 4: fiber1 shutdown channel; verify tx output.
        """
        node_info = self.fiber1.get_client().node_info()
        open_channel_auto_accept_min_ckb_funding_amount = node_info[
            "open_channel_auto_accept_min_ckb_funding_amount"
        ]

        # Step 1: fiber1 open channel with fiber2
        temporary_channel = self.fiber1.get_client().open_channel(
            {
                "peer_id": self.fiber2.get_peer_id(),
                "funding_amount": hex(
                    int(open_channel_auto_accept_min_ckb_funding_amount, 16) - 1
                ),
                "public": True,
            }
        )
        time.sleep(Timeout.POLL_INTERVAL)
        # Step 2: fiber2 accept channel with large shutdown_script args
        self.fiber2.get_client().accept_channel(
            {
                "temporary_channel_id": temporary_channel["temporary_channel_id"],
                "funding_amount": hex(Amount.ckb(1472)),
                "shutdown_script": {
                    "code_hash": "0x9bd7e06f3ecf4be0f2fcd2188b23f1b9fcc88e5d4b65a8637b17723bbda3cce8",
                    "hash_type": "type",
                    "args": "",
                },
            }
        )
        # Step 3: Wait for channel ready; fiber1 send payment to fiber2
        self.wait_for_channel_state(
            self.fiber1.get_client(),
            self.fiber2.get_peer_id(),
            ChannelState.CHANNEL_READY,
            timeout=Timeout.CHANNEL_READY,
        )
        channels = self.fiber2.get_client().list_channels({})
        assert channels["channels"][0]["local_balance"] == "0x0"
        payment_preimage = self.generate_random_preimage()
        invoice_balance = Amount.ckb(0.1)  # 0.1 CKB
        invoice = self.fiber2.get_client().new_invoice(
            {
                "amount": hex(invoice_balance),
                "currency": Currency.FIBD,
                "description": "test invoice generated by node2",
                "expiry": "0xe10",
                "payment_preimage": payment_preimage,
                "hash_algorithm": HashAlgorithm.SHA256,
            }
        )
        before_channel = self.fiber1.get_client().list_channels({})

        payment = self.fiber1.get_client().send_payment(
            {
                "invoice": invoice["invoice_address"],
            }
        )
        self.wait_payment_state(
            self.fiber1,
            payment["payment_hash"],
            PaymentStatus.SUCCESS,
            timeout=Timeout.PAYMENT_SUCCESS,
        )
        after_channel = self.fiber1.get_client().list_channels({})
        assert (
            int(before_channel["channels"][0]["local_balance"], 16)
            - int(after_channel["channels"][0]["local_balance"], 16)
            == invoice_balance
        )

        channels = self.fiber1.get_client().list_channels(
            {"peer_id": self.fiber2.get_peer_id()}
        )
        N1N2_CHANNEL_ID = channels["channels"][0]["channel_id"]
        self.fiber1.get_client().graph_channels()
        before_balance1 = self.Ckb_cli.wallet_get_capacity(
            self.account1["address"]["testnet"]
        )
        before_balance2 = self.Ckb_cli.wallet_get_capacity(
            self.account2["address"]["testnet"]
        )
        # Step 4: fiber1 shutdown channel; verify tx output
        self.fiber1.get_client().shutdown_channel(
            {
                "channel_id": N1N2_CHANNEL_ID,
                "close_script": self.get_account_script(self.Config.ACCOUNT_PRIVATE_1),
                "fee_rate": hex(FeeRate.DEFAULT),
            }
        )
        self.wait_tx_pool(1)
        pool = self.node.getClient().get_raw_tx_pool()
        tx = self.node.getClient().get_transaction(pool["pending"][0])
        assert {
            "capacity": "0x2246665680",
            "lock": {
                "args": "",
                "code_hash": "0x9bd7e06f3ecf4be0f2fcd2188b23f1b9fcc88e5d4b65a8637b17723bbda3cce8",
                "hash_type": "type",
            },
            "type": None,
        } in tx["transaction"]["outputs"]
